A debounce function delays the execution of a given function until a specified amount of time has passed without the function being called again.

```javascript
function debounce(func, wait) {
    let timer;

    return function(...args) {
        const context = this;
        clearTimeout(timer);
        timer = setTimeout(() => func.apply(context, args), wait);
    }
};

// Usage example
const logMessage = debounce((message) => console.log(message), 500);
// Calling this function multiple times within 500ms will only log the last message.
logMessage("Hello, world!");
```
